function cmdStatus() {
    const index = fs.readFileSync(INDEX_FILE, 'utf8');
    const entries = index.split('\n').filter(e => e.length > 0);
    console.log('Staged files:');
    if (entries.length === 0) {
        console.log('(none)');
    } else {
        for (const e of entries) {
            console.log(e);
        }
    }
}

function parseCommit(hash) {
    const commitFile = path.join(COMMITS_DIR, hash);
    if (!fs.existsSync(commitFile)) return null;
    const content = fs.readFileSync(commitFile, 'utf8');
    const lines = content.split('\n');
    let parent = '', timestamp = '', message = '';
    const files = {};
    let inFiles = false;
    for (const line of lines) {
        if (line.startsWith('parent: ')) { parent = line.substring(8); inFiles = false; }
        else if (line.startsWith('timestamp: ')) { timestamp = line.substring(11); inFiles = false; }
        else if (line.startsWith('message: ')) { message = line.substring(9); inFiles = false; }
        else if (line === 'files:') { inFiles = true; }
        else if (inFiles && line.length > 0) {
            const idx = line.lastIndexOf(' ');
            files[line.substring(0, idx)] = line.substring(idx + 1);
        }
    }
    return { parent, timestamp, message, files };
}

function cmdDiff(hash1, hash2) {
    const c1 = parseCommit(hash1);
    const c2 = parseCommit(hash2);
    if (!c1 || !c2) {
        console.log('Invalid commit');
        process.exit(1);
    }
    const allFiles = new Set([...Object.keys(c1.files), ...Object.keys(c2.files)]);
    const sorted = [...allFiles].sort();
    for (const f of sorted) {
        if (!(f in c1.files) && f in c2.files) console.log(`Added: ${f}`);
        else if (f in c1.files && !(f in c2.files)) console.log(`Removed: ${f}`);
        else if (c1.files[f] !== c2.files[f]) console.log(`Modified: ${f}`);
    }
}

function cmdCheckout(hash) {
    const commitFile = path.join(COMMITS_DIR, hash);
    if (!fs.existsSync(commitFile)) {
        console.log('Invalid commit');
        process.exit(1);
    }
    const c = parseCommit(hash);
    for (const [filename, blobHash] of Object.entries(c.files)) {
        const content = fs.readFileSync(path.join(OBJECTS_DIR, blobHash));
        fs.writeFileSync(filename, content);
    }
    fs.writeFileSync(HEAD_FILE, hash);
    fs.writeFileSync(INDEX_FILE, '');
    console.log(`Checked out ${hash}`);
}

function cmdReset(hash) {
    const commitFile = path.join(COMMITS_DIR, hash);
    if (!fs.existsSync(commitFile)) {
        console.log('Invalid commit');
        process.exit(1);
    }
    fs.writeFileSync(HEAD_FILE, hash);
    fs.writeFileSync(INDEX_FILE, '');
    console.log(`Reset to ${hash}`);
}

function cmdRm(filename) {
    const index = fs.readFileSync(INDEX_FILE, 'utf8');
    const entries = index.split('\n').filter(e => e.length > 0);
    if (!entries.includes(filename)) {
        console.log('File not in index');
        process.exit(1);
    }
    const newEntries = entries.filter(e => e !== filename);
    fs.writeFileSync(INDEX_FILE, newEntries.length > 0 ? newEntries.join('\n') + '\n' : '');
}

function cmdShow(hash) {
    const commitFile = path.join(COMMITS_DIR, hash);
    if (!fs.existsSync(commitFile)) {
        console.log('Invalid commit');
        process.exit(1);
    }
    const c = parseCommit(hash);
    console.log(`commit ${hash}`);
    console.log(`Date: ${c.timestamp}`);
    console.log(`Message: ${c.message}`);
    console.log('Files:');
    const sorted = Object.keys(c.files).sort();
    for (const f of sorted) {
        console.log(`  ${f} ${c.files[f]}`);
    }
}

const args = process.argv.slice(2);
const command = args[0];

switch (command) {
    case 'init':
        cmdInit();
        break;
    case 'add':
        cmdAdd(args[1]);
        break;
    case 'commit':
        if (args[1] === '-m' && args[2]) {
            cmdCommit(args[2]);
        } else {
            console.error('Usage: minigit commit -m "<message>"');
            process.exit(1);
        }
        break;
    case 'status':
        cmdStatus();
        break;
    case 'log':
        cmdLog();
        break;
    case 'diff':
        cmdDiff(args[1], args[2]);
        break;
    case 'checkout':
        cmdCheckout(args[1]);
        break;
    case 'reset':
        cmdReset(args[1]);
        break;
    case 'rm':
        cmdRm(args[1]);
        break;
    case 'show':
        cmdShow(args[1]);
        break;
    default:
        console.error('Unknown command');
        process.exit(1);
}

