const command = args[0];

switch (command) {
    case 'init':
        cmdInit();
        break;
    case 'add':
        cmdAdd(args[1]);
        break;
    case 'commit':
        if (args[1] === '-m' && args[2]) {
            cmdCommit(args[2]);
        } else {
            console.error('Usage: minigit commit -m "<message>"');
            process.exit(1);
        }
        break;
    case 'log':
        cmdLog();
        break;
    default:
        console.error('Unknown command');
        process.exit(1);
}
